package service;

import dao.HabitDAO;
import model.Habit;
import model.Habit.Priority;

import java.time.LocalDate;
import java.util.List;

public class HabitService {

    private final HabitDAO habitDAO = new HabitDAO();

    public Habit createHabit(String name, String description, LocalDate dueDate, Priority priority) {
        // id is generated by DB, so use 0 as placeholder
        Habit h = new Habit(0, name, description, dueDate, priority);
        habitDAO.insert(h);
        return h;
    }

    public List<Habit> listHabits() {
        return habitDAO.findAll();
    }

    public boolean markComplete(int id) {
        return habitDAO.setCompleted(id, true);
    }

    public boolean markIncomplete(int id) {
        return habitDAO.setCompleted(id, false);
    }

    // --- NEW METHODS ---
    public Habit findHabitById(int id) {
        return habitDAO.findById(id);
    }

    public boolean updateHabit(int id, String name, String description, LocalDate dueDate, Priority priority) {
        return habitDAO.update(id, name, description == null ? "" : description, dueDate, priority);
    }

    public boolean deleteHabit(int id) {
        return habitDAO.deleteById(id);
    }
}
